/**
 * @name XStream deserialization taint flow to OS command execution
 * @description XStream fromXML/unmarshal can deserialize XML into objects that trigger command execution
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-deserialization-to-exec
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XStreamDeserToExecConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // XStream fromXML / unmarshal calls - the return value or argument is tainted
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("com.thoughtworks.xstream", "XStream") and
      mc.getMethod().hasName("fromXML") and
      source.asExpr() = mc
    )
    or
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.thoughtworks.xstream", "XStream") and
      mc.getMethod().hasName("unmarshal") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Runtime.exec sinks
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ProcessBuilder construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module XStreamDeserToExecFlow = TaintTracking::Global<XStreamDeserToExecConfig>;
import XStreamDeserToExecFlow::PathGraph

from XStreamDeserToExecFlow::PathNode source, XStreamDeserToExecFlow::PathNode sink
where XStreamDeserToExecFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XStream deserialization result flows to OS command execution from $@.", source.getNode(), "XStream.fromXML"

/**
 * @name XStream DefaultMapper.realClass taint flow from XML reader to class instantiation
 * @description XML class name from reader flows into Class.forName enabling arbitrary class instantiation
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-xml-to-class-loading
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module XStreamClassLoadConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // XML reader getValue/getNodeName calls within XStream - these return XML-derived strings
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getValue") or
        mc.getMethod().hasName("getNodeName") or
        mc.getMethod().hasName("getAttribute") or
        mc.getMethod().hasName("getAttributeName") or
        mc.getMethod().hasName("peekNextChild")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.thoughtworks.xstream.io", "HierarchicalStreamReader") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Class.forName with the XML-derived name
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ClassLoader.loadClass with the XML-derived name
    exists(MethodCall mc |
      mc.getMethod().hasName("loadClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module XStreamClassLoadFlow = TaintTracking::Global<XStreamClassLoadConfig>;
import XStreamClassLoadFlow::PathGraph

from XStreamClassLoadFlow::PathNode source, XStreamClassLoadFlow::PathNode sink
where XStreamClassLoadFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XML-derived class name flows to class loading from $@.", source.getNode(), "XML reader"

/**
 * @name XStream DynamicProxyConverter - arbitrary interface proxy creation from XML
 * @description DynamicProxyConverter creates proxies for attacker-controlled interface names from XML,
 *              enabling OS command injection via ProcessBuilder/Runtime gadget chains (CVE-2013-7285)
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-dynamic-proxy-cmd-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module DynamicProxyConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // XML reader getValue calls in DynamicProxyConverter context
    exists(MethodCall mc |
      (mc.getMethod().hasName("getValue") or mc.getMethod().hasName("getAttribute")) and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "com.thoughtworks.xstream.converters.extended", "DynamicProxyConverter"
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Class.forName - loading arbitrary class from XML-derived name
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Proxy.newProxyInstance - creating a dynamic proxy with attacker-controlled interfaces
    exists(MethodCall mc |
      mc.getMethod().hasName("newProxyInstance") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Proxy") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // loadClass
    exists(MethodCall mc |
      mc.getMethod().hasName("loadClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module DynamicProxyFlow = TaintTracking::Global<DynamicProxyConfig>;
import DynamicProxyFlow::PathGraph

from DynamicProxyFlow::PathNode source, DynamicProxyFlow::PathNode sink
where DynamicProxyFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XML-derived value in DynamicProxyConverter flows to class/proxy creation from $@.", source.getNode(), "XML reader value"

/**
 * @name XStream TreeUnmarshaller - XML node name to class instantiation
 * @description XStream's TreeUnmarshaller converts XML element names to class names and instantiates them without restriction
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-tree-unmarshaller-class-instantiation
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module TreeUnmarshallerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // XML reader methods that return element/attribute names or values
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getNodeName") or
        mc.getMethod().hasName("getValue") or
        mc.getMethod().hasName("getAttribute")
      ) and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName()
        .matches("com.thoughtworks.xstream%") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // newInstance() - actual object instantiation
    exists(MethodCall mc |
      mc.getMethod().hasName("newInstance") and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang.reflect", "Constructor")
      ) and
      sink.asExpr() = mc.getQualifier()
    )
    or
    // reflectionProvider.newInstance  
    exists(MethodCall mc |
      mc.getMethod().hasName("newInstance") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "com.thoughtworks.xstream.converters.reflection", "ReflectionProvider"
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module TreeUnmarshallerFlow = TaintTracking::Global<TreeUnmarshallerConfig>;
import TreeUnmarshallerFlow::PathGraph

from TreeUnmarshallerFlow::PathNode source, TreeUnmarshallerFlow::PathNode sink
where TreeUnmarshallerFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XML element name flows to object instantiation (arbitrary class) from $@.", source.getNode(), "XML reader"

/**
 * @name XStream JavaClassConverter - XML text to Class.forName without restriction
 * @description JavaClassConverter converts XML text directly to Class objects via mapper.realClass()
 *              which calls Class.forName(), enabling instantiation of any class including ProcessBuilder
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-javaclass-to-forname
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module JavaClassConverterConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getValue() on the reader in JavaClassConverter.fromString / unmarshal
    exists(MethodCall mc |
      mc.getMethod().hasName("getValue") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "com.thoughtworks.xstream.converters.extended", "JavaClassConverter"
      ) and
      source.asExpr() = mc
    )
    or
    // SingleValueConverterWrapper.fromString wraps JavaClassConverter
    exists(MethodCall mc |
      mc.getMethod().hasName("fromString") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName(
        "com.thoughtworks.xstream.converters", "SingleValueConverterWrapper"
      ) and
      source.asExpr() = mc.getAnArgument()
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("loadClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module JavaClassConverterFlow = TaintTracking::Global<JavaClassConverterConfig>;
import JavaClassConverterFlow::PathGraph

from JavaClassConverterFlow::PathNode source, JavaClassConverterFlow::PathNode sink
where JavaClassConverterFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "JavaClassConverter XML value flows to Class.forName from $@.", source.getNode(), "XML text value"

/**
 * @name XStream SerializableConverter calls readObject/readResolve on arbitrary deserialized objects
 * @description SerializableConverter and SerializationMethodInvoker invoke serialization lifecycle 
 *              methods on arbitrary deserialized class instances, completing the gadget chain 
 *              for OS command injection via EventHandler -> Runtime.exec
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-serializable-readobject-gadget
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module SerializableGadgetConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Class loaded from XML via DefaultMapper.realClass / Class.forName
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("com.thoughtworks.xstream%") and
      source.asExpr() = mc
    )
    or
    // realClass() calls in mapper chain
    exists(MethodCall mc |
      mc.getMethod().hasName("realClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("com.thoughtworks.xstream.mapper", "Mapper") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // newInstance on a Class object - instantiates the loaded class
    exists(MethodCall mc |
      mc.getMethod().hasName("newInstance") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getQualifier()
    )
    or
    // reflectionProvider.newInstance(clazz) 
    exists(MethodCall mc |
      mc.getMethod().hasName("newInstance") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // callReadObject / callReadResolve in SerializationMethodInvoker
    exists(MethodCall mc |
      (mc.getMethod().hasName("callReadObject") or 
       mc.getMethod().hasName("callReadResolve") or
       mc.getMethod().hasName("callWriteReplace")) and
      mc.getMethod().getDeclaringType().hasQualifiedName(
        "com.thoughtworks.xstream.converters.reflection", "SerializationMethodInvoker"
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module SerializableGadgetFlow = TaintTracking::Global<SerializableGadgetConfig>;
import SerializableGadgetFlow::PathGraph

from SerializableGadgetFlow::PathNode source, SerializableGadgetFlow::PathNode sink
where SerializableGadgetFlow::flowPath(source, sink)
select sink.getNode(), source, sink, 
  "Loaded class flows to object instantiation/lifecycle method invocation from $@, enabling gadget chain execution.", 
  source.getNode(), "class loaded from XML"
